package spark.serialization;

import org.junit.Assert;
import org.junit.Test;
import org.junit.runner.RunWith;
import org.mockito.Mockito;
import org.mockito.runners.MockitoJUnitRunner;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;

@RunWith(MockitoJUnitRunner.class)
public class InputStreamSerializerTest {

    private InputStreamSerializer serializer = new InputStreamSerializer();

    @Test
    public void testProcess_copiesData() throws IOException {
        // Given: Valid representative inputs
        byte[] bytes = "Test data for functional test".getBytes();
        ByteArrayInputStream input = new ByteArrayInputStream(bytes);
        ByteArrayOutputStream output = new ByteArrayOutputStream();

        // When: Call InputStreamSerializer.process(...) directly
        serializer.process(output, input);

        // Then: Data effect - output stream contains the same bytes as input
        Assert.assertArrayEquals(bytes, output.toByteArray());
    }

    @Test(expected = NullPointerException.class)
    public void testProcess_withNullOutputStream_throwsException() throws IOException {
        // Given: Null for reference parameter (OutputStream)
        ByteArrayInputStream input = new ByteArrayInputStream("data".getBytes());

        // When: Call InputStreamSerializer.process(...) with null OutputStream
        // Then: Expect NullPointerException to be thrown
        serializer.process(null, input);
    }

    @Test(expected = ClassCastException.class)
    public void testProcess_withNonInputStreamElement_throwsException() throws IOException {
        // Given: Invalid element that is not an InputStream
        ByteArrayOutputStream output = new ByteArrayOutputStream();
        Object invalidElement = "Not an InputStream";

        // When: Call InputStreamSerializer.process(...) with non-InputStream element
        // Then: Expect ClassCastException to be thrown
        serializer.process(output, invalidElement);
    }

    @Test
    public void testProcess_withEmptyInputStream() throws IOException {
        // Given: Empty InputStream (boundary value)
        byte[] emptyBytes = new byte[0];
        ByteArrayInputStream input = new ByteArrayInputStream(emptyBytes);
        ByteArrayOutputStream output = new ByteArrayOutputStream();

        // When: Call InputStreamSerializer.process(...) with empty InputStream
        serializer.process(output, input);

        // Then: Output stream should also be empty
        Assert.assertEquals(0, output.toByteArray().length);
    }

    @Test(expected = IOException.class)
    public void testProcess_withClosedInputStream_throwsException() throws IOException {
        // Given: Closed InputStream (simulated via mock)
        InputStream mockInputStream = Mockito.mock(InputStream.class);
        Mockito.doThrow(new IOException("Stream closed")).when(mockInputStream).read(Mockito.any(byte[].class));
        Mockito.doThrow(new IOException("Stream closed")).when(mockInputStream).read(Mockito.any(byte[].class), Mockito.anyInt(), Mockito.anyInt());

        ByteArrayOutputStream output = new ByteArrayOutputStream();

        // When: Call InputStreamSerializer.process(...) with closed InputStream
        // Then: Expect IOException to be thrown
        serializer.process(output, mockInputStream);
    }
}
